// 典型问题：选择最多互不重叠的区间
// 输入：intervals = [[l1, r1], [l2, r2], ...]
// 输出：最多能选择多少个互不重叠的区间
int maxNonOverlappingIntervals(vector<vector<int>>& intervals) {
    // 按右端点排序
    sort(intervals.begin(), intervals.end(), [](const vector<int>& a, const vector<int>& b) {
        return a[1] < b[1];
    });
    int count = 0, lastEnd = -1e9;
    for (auto& interval : intervals) {
        if (interval[0] > lastEnd) {
            count++;
            lastEnd = interval[1];
        }
    }
    return count;
}

// 典型问题：用最少的点覆盖所有区间
// 输入：intervals = [[l1, r1], [l2, r2], ...]
// 输出：最少需要多少个点，使得每个区间至少包含一个点
int minPointsCoverIntervals(vector<vector<int>>& intervals) {
    // 按右端点排序
    sort(intervals.begin(), intervals.end(), [](const vector<int>& a, const vector<int>& b) {
        return a[1] < b[1];
    });
    int points = 0, lastPoint = -1e9;
    for (auto& interval : intervals) {
        if (interval[0] > lastPoint) {
            points++;
            lastPoint = interval[1];
        }
    }
    return points;
}

// 典型问题：构造特定序列
// 输入：n, k 等参数
// 输出：满足条件的序列
vector<int> constructSequence(int n, int k) {
    vector<int> res;
    // 根据题目规则构造
    // 例如：交替放置大小值使相邻乘积最大
    for (int i = 1; i <= n/2; i++) {
        res.push_back(i);
        res.push_back(n - i + 1);
    }
    if (n % 2) res.push_back(n/2 + 1);
    return res;
}

// 典型问题：选择k个元素使和最大，但有选择限制
// 输入：数组a, 限制条件
// 输出：最大和
long long maxSumWithLimits(vector<int>& a, int k) {
    priority_queue<int, vector<int>, greater<int>> pq; // 小顶堆
    long long sum = 0;
    for (int i = 0; i < a.size(); i++) {
        pq.push(a[i]);
        sum += a[i];
        if (pq.size() > k) {
            sum -= pq.top(); // 反悔：移除最小的
            pq.pop();
        }
    }
    return sum;
}

