// 输入：石子堆数组a
// 输出：先手是否必胜
bool canWinNim(vector<int>& a) {
    int xor_sum = 0;
    for (int x : a) xor_sum ^= x;
    return xor_sum != 0; // 异或和非0则先手必胜
}

